    cat = None
    # check science/tech first
    if any(kw in text for kw in science_keywords):
        cat = 'Science/Technology'
    elif any(kw in text for kw in sports_keywords):
        cat = 'Sports'
    elif any(kw in text for kw in business_keywords):
        cat = 'Business'
